`timescale 1ns / 1ps

module tb_closing3x3(
    );

// Input signals generated by hdmi_in
wire rx_pclk;
wire rx_de;
wire rx_hsync;
wire rx_vsync;
wire [7:0] rx_red;
wire [7:0] rx_green;
wire [7:0] rx_blue;

// Output signals consumed by hdmi_out
wire tx_de;
wire tx_hsync;
wire tx_vsync;
wire [7:0] tx_red;
wire [7:0] tx_green;
wire [7:0] tx_blue;

// Reset signal for DUT
reg tb_rst;

// Intermediate signals from DUT
wire closing;
wire closing_de;
wire closing_vsync;
wire closing_hsync;

// Registers for processed output color
reg [7:0] closing_r;
reg [7:0] closing_g;
reg [7:0] closing_b;

// Instantiate the input generator (assuming it exists)
// It provides clock and input video signals
hdmi_in file_input (
    .hdmi_clk(rx_pclk),
    .hdmi_de(rx_de),
    .hdmi_hs(rx_hsync),
    .hdmi_vs(rx_vsync),
    .hdmi_r(rx_red),
    .hdmi_g(rx_green),
    .hdmi_b(rx_blue)
    );

// Instantiate the Device Under Test (DUT)
closing3x3 #
(
	.H_SIZE(10'd83) // Example parameter, adjust if needed
)
close33
(
	.clk(rx_pclk),
	.ce(1'b1), // Assuming clock enable is always active for test
	.rst(tb_rst), // Connect testbench reset
	.mask((rx_red == 8'hFF) ? 1'b1 : 1'b0), // Example mask logic
	.in_de(rx_de),
	.in_vsync(rx_vsync),
	.in_hsync(rx_hsync),

	.closed(closing),
	.out_de(closing_de),
	.out_vsync(closing_vsync),
	.out_hsync(closing_hsync)
);

// Generate reset pulse
initial begin
    tb_rst = 1'b1;
    #20; // Hold reset for 20 time units
    tb_rst = 1'b0;
end

// Process the 'closing' output to generate RGB output
always @(posedge rx_pclk) begin
    if (tb_rst) begin
        closing_r <= 8'h00;
        closing_g <= 8'h00;
        closing_b <= 8'h00;
    end else begin
        closing_r <= (closing) ? 8'hFF : 8'h00;
        closing_g <= (closing) ? 8'hFF : 8'h00;
        closing_b <= (closing) ? 8'hFF : 8'h00;
    end
end

// Assign processed signals to output interface wires
assign tx_de 		= closing_de;
assign tx_hsync 	= closing_hsync;
assign tx_vsync 	= closing_vsync;
assign tx_red       = closing_r;
assign tx_green     = closing_g;
assign tx_blue      = closing_b;

// Instantiate the output consumer (assuming it exists)
hdmi_out file_output (
    .hdmi_clk(rx_pclk),
    .hdmi_vs(tx_vsync),
    .hdmi_hs(tx_hsync), // Assuming hdmi_out needs hsync
    .hdmi_de(tx_de),
    .hdmi_data({tx_red, tx_green, tx_blue}) // Assuming 24-bit data interface
    // Adjust .hdmi_data format if needed, e.g., {8'b0, tx_red, tx_green, tx_blue} for 32-bit
    );

endmodule